@app.route('/users', methods=['GET', 'POST'])
def handle_users():
    """
    Endpoint to retrieve or create users, demonstrating SQL query capture.
    """
    conn = sqlite3.connect(DATABASE_NAME)
    cursor = conn.cursor()

    if request.method == 'GET':
        cursor.execute("SELECT id, name, email FROM users")
        users = [{"id": row[0], "name": row[1], "email": row[2]} for row in cursor.fetchall()]
        conn.close()
        return jsonify(users)
    elif request.method == 'POST':
        data = request.get_json()
        if not data or 'name' not in data or 'email' not in data:
            return jsonify({"error": "Name and email are required"}), 400
        try:
            cursor.execute("INSERT INTO users (name, email) VALUES (?, ?)", (data['name'], data['email']))
            conn.commit()
            new_user_id = cursor.lastrowid
            conn.close()
            return jsonify({"message": "User created", "id": new_user_id, "name": data['name'], "email": data['email']}), 201
        except sqlite3.IntegrityError:
            conn.close()
            return jsonify({"error": "User with this email already exists"}), 409
        except Exception as e:
            # Capture any other exception explicitly for demonstration
            if client:
                client.capture_exception()
            conn.close()
            return jsonify({"error": str(e)}), 500

@app.route('/user/<int:user_id>')
def get_user(user_id):
    """
    Endpoint to retrieve a single user by ID.
    Demonstrates parameterised SQL query capture.
    """
    conn = sqlite3.connect(DATABASE_NAME)
    cursor = conn.cursor()
    cursor.execute("SELECT id, name, email FROM users WHERE id = ?", (user_id,))
    user = cursor.fetchone()
    conn.close()
    if user:
        return jsonify({"id": user[0], "name": user[1], "email": user[2]})
    return jsonify({"message": "User not found"}), 404

